  vect(crs = "epsg:4326") |&gt;
  terra::project("epsg:32630")
data_all &lt;- terra::extract(r0, coord) |&gt;
  rename(id = Annual_Mean_LST) |&gt;
  select(id) |&gt;
  bind_cols(data_all) |&gt;
